    const tempPassword = `Doctor@${Math.floor(10000 + Math.random() * 90000)}`;

    // Lazy-init the secondary Firebase app (same config, different name)
    if (!secondaryApp) {
        const { initializeApp, getApps } = await import('firebase/app');
        const existingApps = getApps().map(a => a.name);
        if (!existingApps.includes('secondary')) {
            const { default: primaryApp } = await import('./config');
            const config = primaryApp?.options || {
                apiKey: "AIzaSyBB2m8e_mqah6lF8-693f7YuundPxuJIGU",
                authDomain: "vibe-coder-1e4c8.firebaseapp.com",
                projectId: "vibe-coder-1e4c8",
