                messagingSenderId: "124101167420",
                appId: "1:124101167420:web:d120259e05a42370e2f639"
            };
            secondaryApp = initializeApp(config, 'secondary');
        } else {
            const { getApp } = await import('firebase/app');
            secondaryApp = getApp('secondary');
        }
    }

    const { getAuth, createUserWithEmailAndPassword: createDoc, signOut: signOutSecondary } = await import('firebase/auth');
    const secondaryAuth = getAuth(secondaryApp);

    let uid;
    try {
        const cred = await createDoc(secondaryAuth, email, tempPassword);
        uid = cred.user.uid;
        // Sign out the secondary auth immediately to clean up
        await signOutSecondary(secondaryAuth);
    } catch (err) {
        throw err;
    }

    // Write Firestore records
    const now = serverTimestamp();
    const doctorRecord = {
        uid,
        name,
        email,
        department: department || '',
        phone: phone || '',
        hospitalId,
        role: 'doctor',
        status: 'ACTIVE',
        createdAt: now,
    };

    await Promise.all([
        // Global doctors collection
        setDoc(doc(db, 'doctors', uid), doctorRecord),
        // Hospital subcollection
        setDoc(doc(db, 'hospitals', hospitalId, 'doctors', uid), {
            uid, name, email, department: department || '', phone: phone || '',
