import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import Button from '../components/Button';
import {
    Users, Clock, Activity, Settings, LogOut,
    CheckCircle, Camera, Upload, Trash2,
    ChevronRight, Bell, Calendar, ShieldCheck
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import ConfirmModal from '../components/ConfirmModal';
import Input from '../components/Input';
import { getAIResponse } from '../utils/AIService';
import { useRef, useEffect } from 'react';

const DoctorDashboard = () => {
    const navigate = useNavigate();
    const {
        user, loading, appointments, updateAppointmentStatus, updateProfile, logout,
        doctorStatus, setDoctorStatus, autoApprove, setAutoApprove
    } = useAuth();

    const [activeTab, setActiveTab] = useState('queue'); // 'queue' | 'ai-bot' | 'settings'
    const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
    const [profileMsg, setProfileMsg] = useState({ type: '', text: '' });

    // AI Chat State
    const [chatHistory, setChatHistory] = useState([]);
    const [chatInput, setChatInput] = useState('');
    const [isAILoading, setIsAILoading] = useState(false);
    const chatEndRef = useRef(null);

    const scrollToBottom = () => {
        chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [chatHistory, isAILoading]);

    const [profileForm, setProfileForm] = useState({
        name: user?.name || '',
        inChargeName: user?.inChargeName || '',
        phone: user?.phone || user?.primaryPhone || '',
        secondaryPhone: user?.secondaryPhone || ''
    });

    useEffect(() => {
        if (!loading && !user) navigate('/login');
    }, [user, loading, navigate]);

    if (loading || !user) return null;

    const myAppointments = appointments.filter(a => a.doctorId === user.id);
    const pending = myAppointments.filter(a => a.status === 'Accepted' || a.status === 'Confirmed');

    const handleSendChat = async (e) => {
        e.preventDefault();
        if (!chatInput.trim() || isAILoading) return;

        const userMsg = { role: 'user', text: chatInput };
        const newHistory = [...chatHistory, userMsg];
        setChatHistory(newHistory);
        setChatInput('');
        setIsAILoading(true);

        try {
            // Inject clinical context
            const clinicalContext = `
                CURRENT CONTEXT:
                Doctor: Dr. ${user.name}
                Queue: ${pending.length} patients pending.
                Patient Details: ${pending.map(p => `Patient #${p.id} (${p.userName}) at ${p.time}`).join(', ') || 'Queue is currently empty.'}
                Status: ${doctorStatus}
                Auto-Approve: ${autoApprove ? 'ON' : 'OFF'}
            `;

            const historyWithContext = [
                { role: 'user', text: `SYSTEM CONTEXT (INTERNAL): ${clinicalContext}\n\nUSER QUERY: ${chatInput}` },
            ];

            const aiResponse = await getAIResponse(newHistory, 'doctor');
            setChatHistory([...newHistory, { role: 'model', text: aiResponse }]);
        } catch (error) {
            console.error("AI Error:", error);
            setChatHistory([...newHistory, { role: 'model', text: "I'm having trouble analyzing the clinical data right now. Please try again." }]);
        } finally {
            setIsAILoading(false);
        }
    };

    const handleUpdateProfile = (e) => {
        e.preventDefault();
        setProfileMsg({ type: '', text: '' });
        const res = updateProfile(profileForm);
        if (res.success) {
            setProfileMsg({ type: 'success', text: 'Profile updated successfully!' });
        } else {
            setProfileMsg({ type: 'error', text: res.message });
        }
    };

    return (
        <div className="min-h-screen bg-[#fafbfc] pb-24">
            {/* Minimalist Clinical Header */}
            <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-100 px-6 py-4 flex items-center justify-between">
                <div>
                    <h1 className="text-xl font-black text-slate-800 tracking-tight">Dr. {user.name}</h1>
                    <p className="text-[11px] font-bold text-teal-600 uppercase tracking-widest flex items-center gap-1">
                        <ShieldCheck size={12} strokeWidth={3} /> Doctor's Portal
                    </p>
                </div>
                <div className="flex items-center gap-4">
                    <div className="hidden sm:flex flex-col items-end mr-2">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Doctor ID</span>
                        <span className="text-xs font-bold text-slate-700">{user.code}</span>
                    </div>
                    <button
                        onClick={() => setShowLogoutConfirm(true)}
                        className="bg-rose-50 text-rose-500 px-4 py-2 rounded-full text-xs font-black uppercase tracking-wider hover:bg-rose-100 transition-colors flex items-center gap-2"
                    >
                        <LogOut size={14} strokeWidth={2.5} /> Logout
                    </button>
                </div>
            </header>

            <main className="max-w-4xl mx-auto p-6">
                {/* Navigation Tabs */}
                <div className="flex gap-8 mb-8 border-b border-slate-100 relative">
                    {[
                        { id: 'queue', label: 'Queue', icon: <Users size={18} /> },
                        { id: 'ai-bot', label: 'AI Reminder Bot', icon: <Activity size={18} /> },
                        { id: 'settings', label: 'Profile Settings', icon: <Settings size={18} /> }
                    ].map(tab => (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id)}
                            className={`flex items-center gap-2 py-4 text-sm font-bold transition-all relative ${activeTab === tab.id ? 'text-teal-600' : 'text-slate-400'
                                }`}
                        >
                            {tab.icon}
                            {tab.label}
                            {activeTab === tab.id && (
                                <motion.div
                                    layoutId="doctorTabGlow"
                                    className="absolute bottom-0 left-0 right-0 h-1 bg-teal-500 rounded-t-full shadow-[0_0_12px_rgba(20,184,166,0.6)]"
                                />
                            )}
                        </button>
                    ))}
                </div>

                {/* Session Status Card */}
                <div className="bg-white rounded-[32px] p-6 shadow-sm border border-slate-100 mb-8">
                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6">
                        <div className="space-y-3">
                            <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest px-1">Session Status</p>
                            <div className="flex flex-wrap gap-2">
                                {[
                                    { label: 'Available', color: 'teal', glow: 'shadow-teal-500/20' },
                                    { label: 'In Appointment', color: 'blue', glow: 'shadow-blue-500/20' },
                                    { label: 'Offline', color: 'slate', glow: 'shadow-slate-500/20' }
                                ].map(s => (
                                    <button
                                        key={s.label}
                                        onClick={() => setDoctorStatus(s.label)}
                                        className={`px-4 py-2 rounded-2xl text-xs font-bold transition-all ${doctorStatus === s.label
                                            ? `bg-${s.color}-50 text-${s.color}-600 shadow-lg ${s.glow} border-${s.color}-100`
                                            : 'bg-transparent text-slate-400 border border-slate-100 hover:bg-slate-50'
                                            }`}
                                    >
                                        <div className="flex items-center gap-2">
                                            <div className={`w-1.5 h-1.5 rounded-full ${doctorStatus === s.label ? `bg-${s.color}-500 animate-pulse` : 'bg-slate-300'}`} />
                                            {s.label}
                                        </div>
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="h-12 w-[1px] bg-slate-100 hidden sm:block" />

                        <div className="flex items-center justify-between sm:justify-end gap-4 flex-1">
                            <div className="text-right">
                                <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Auto-Approve</p>
                                <p className="text-[10px] text-slate-500 font-medium">Bypass manual accept</p>
                            </div>
                            <button
                                onClick={() => setAutoApprove(!autoApprove)}
                                className={`w-14 h-8 rounded-full transition-all relative ${autoApprove ? 'bg-teal-500 shadow-lg shadow-teal-500/30' : 'bg-slate-200'
                                    }`}
                            >
                                <motion.div
                                    className="w-6 h-6 bg-white rounded-full absolute top-1 left-1 shadow-sm"
                                    animate={{ x: autoApprove ? 24 : 0 }}
                                />
                            </button>
                        </div>
                    </div>
                </div>

                <AnimatePresence mode="wait">
                    {activeTab === 'queue' && (
                        <motion.div
                            key="queue"
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95 }}
                            className="space-y-4"
                        >
                            <h3 className="text-lg font-black text-slate-800 px-1">Clinical Queue</h3>
                            {pending.length > 0 ? (
                                pending.map(appt => (
                                    <div key={appt.id} className="bg-white p-5 rounded-[28px] border border-slate-100 shadow-sm flex items-center justify-between group hover:border-teal-100 transition-colors">
                                        <div className="flex items-center gap-4">
                                            <div className="w-12 h-12 rounded-2xl bg-teal-50 text-teal-500 flex items-center justify-center">
                                                <Users size={20} />
                                            </div>
                                            <div>
                                                <p className="text-sm font-black text-slate-800">#{appt.id} ΓÇó {appt.userName || 'Patient'}</p>
                                                <p className="text-xs text-slate-500 font-bold flex items-center gap-2">
                                                    <Clock size={12} /> {appt.time || '10:00 AM'}
                                                </p>
                                            </div>
                                        </div>
                                        {appt.status === 'Confirmed' ? (
                                            <button
                                                onClick={() => updateAppointmentStatus(appt.id, 'Accepted')}
                                                className="bg-teal-600 text-white px-6 py-2.5 rounded-2xl text-xs font-black shadow-lg shadow-teal-600/20 active:scale-95 transition-all"
                                            >
                                                Start Case
                                            </button>
                                        ) : (
                                            <button
                                                onClick={() => navigate(`/prescribe/${appt.id}`)}
                                                className="flex items-center gap-2 text-teal-600 font-black text-xs hover:bg-teal-50 px-4 py-2 rounded-xl transition-colors"
                                            >
                                                Open Record <ChevronRight size={16} />
                                            </button>
                                        )}
                                    </div>
                                ))
                            ) : (
                                <div className="text-center py-20 bg-white rounded-[40px] border border-dashed border-slate-200">
                                    <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-200">
                                        <Calendar size={40} />
                                    </div>
                                    <h4 className="text-slate-400 font-black uppercase tracking-widest text-xs">No Appointments Left</h4>
                                    <p className="text-slate-300 text-[11px] mt-1">Excellent! Your queue is clear.</p>
                                </div>
                            )}
                        </motion.div>
                    )}

                    {activeTab === 'settings' && (
                        <motion.form
                            key="settings"
                            initial={{ opacity: 0, scale: 0.98 }}
                            animate={{ opacity: 1, scale: 1 }}
                            onSubmit={handleUpdateProfile}
                            className="bg-white rounded-[40px] p-8 shadow-sm border border-slate-50 flex flex-col gap-8"
                        >
                            <div className="flex items-center justify-between mb-2">
                                <h3 className="text-lg font-black text-slate-800">Clinical Configuration</h3>
                                <button type="button" onClick={() => alert('Feature coming soon')} className="text-teal-600 text-xs font-black uppercase tracking-tighter flex items-center gap-1">
                                    <Camera size={14} /> Update Photo
                                </button>
                            </div>

                            {profileMsg.text && (
                                <div className={`p-4 rounded-2xl text-xs font-bold ${profileMsg.type === 'success' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                                    {profileMsg.text}
                                </div>
                            )}

                            <div className="grid grid-cols-2 gap-6">
                                <Input
                                    label="Full Name"
                                    value={profileForm.name}
                                    onChange={e => setProfileForm({ ...profileForm, name: e.target.value })}
                                />
                                <Input
                                    label="Official Email"
                                    value={user.email}
                                    disabled
                                />
                                <Input
                                    label="Primary Phone"
                                    value={profileForm.phone}
                                    onChange={e => setProfileForm({ ...profileForm, phone: e.target.value })}
                                />
                                <Input
                                    label="Secondary Phone"
                                    value={profileForm.secondaryPhone}
                                    onChange={e => setProfileForm({ ...profileForm, secondaryPhone: e.target.value })}
                                />
                            </div>

                            <div className="pt-6 border-t border-slate-50 flex gap-4">
                                <button type="submit" className="bg-teal-600 text-white px-8 py-4 rounded-[20px] text-sm font-black shadow-xl shadow-teal-600/20 active:scale-95 transition-all">
                                    Update Clinical Metadata
                                </button>
                                <button type="button" onClick={() => navigate('/')} className="px-8 py-4 text-slate-400 text-sm font-bold active:scale-95 transition-all">
                                    Preview Profile
                                </button>
                            </div>
                        </motion.form>
                    )}

                    {activeTab === 'ai-bot' && (
                        <motion.div
                            key="ai-bot"
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="bg-slate-900 rounded-[40px] p-6 text-white relative overflow-hidden flex flex-col min-h-[500px]"
                        >
                            {/* AI Header */}
                            <div className="relative z-10 flex items-center justify-between mb-6">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 bg-teal-500/20 text-teal-400 rounded-2xl flex items-center justify-center border border-teal-500/30">
                                        <Activity size={24} />
                                    </div>
                                    <div>
                                        <h3 className="text-lg font-black">Clinical Intel</h3>
                                        <div className="flex items-center gap-2">
                                            <div className="w-1.5 h-1.5 rounded-full bg-teal-500 animate-pulse" />
                                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Active Assistant</p>
                                        </div>
                                    </div>
                                </div>
                                <Activity size={20} className="text-teal-500/20" />
                            </div>

                            {/* Chat Messages */}
                            <div className="flex-1 overflow-y-auto space-y-4 mb-6 pr-2 custom-scrollbar max-h-[350px]">
                                {chatHistory.length === 0 ? (
                                    <div className="h-full flex flex-col items-center justify-center text-center p-8 space-y-4 opacity-50">
                                        <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center">
                                            <Bell size={24} className="text-teal-400" />
                                        </div>
                                        <div>
                                            <p className="text-sm font-bold">How can I assist you today, Dr. {user.name}?</p>
                                            <p className="text-[10px] text-slate-400 mt-1 uppercase tracking-tighter">Queue Analysis ΓÇó Patient History ΓÇó Clinical Guidelines</p>
                                        </div>
                                    </div>
                                ) : (
                                    chatHistory.map((msg, i) => (
                                        <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                            <div className={`max-w-[85%] p-4 rounded-3xl text-sm ${msg.role === 'user'
                                                ? 'bg-teal-600 text-white rounded-tr-none'
                                                : 'bg-white/5 border border-white/10 text-slate-200 rounded-tl-none'
                                                }`}>
                                                <p className="leading-relaxed">{msg.text}</p>
                                            </div>
                                        </div>
                                    ))
                                )}
                                {isAILoading && (
                                    <div className="flex justify-start">
                                        <div className="bg-white/5 border border-white/10 p-4 rounded-3xl rounded-tl-none flex gap-1">
                                            <div className="w-1.5 h-1.5 bg-teal-400 rounded-full animate-bounce" />
                                            <div className="w-1.5 h-1.5 bg-teal-400 rounded-full animate-bounce [animation-delay:0.2s]" />
                                            <div className="w-1.5 h-1.5 bg-teal-400 rounded-full animate-bounce [animation-delay:0.4s]" />
                                        </div>
                                    </div>
                                )}
                                <div ref={chatEndRef} />
                            </div>

                            {/* Chat Input */}
                            <div className="relative z-10 group">
                                <form onSubmit={handleSendChat} className="flex gap-2">
                                    <input
                                        type="text"
                                        value={chatInput}
                                        onChange={(e) => setChatInput(e.target.value)}
                                        placeholder="Ask about your queue or patients..."
                                        className="flex-1 bg-white/5 border border-white/10 rounded-2xl px-5 py-3 text-sm focus:outline-none focus:border-teal-500/50 transition-all placeholder:text-slate-600"
                                    />
                                    <button
                                        type="submit"
                                        disabled={!chatInput.trim() || isAILoading}
                                        className="bg-teal-600 hover:bg-teal-500 disabled:opacity-50 disabled:hover:bg-teal-600 text-white px-5 rounded-2xl transition-all shadow-lg shadow-teal-900/40"
                                    >
                                        <ChevronRight size={20} />
                                    </button>
                                </form>
                            </div>

                            {/* Decorative background elements */}
                            <div className="absolute top-0 right-0 w-64 h-64 bg-teal-500/10 blur-[100px] -mr-32 -mt-32" />
                            <div className="absolute bottom-0 left-0 w-64 h-64 bg-teal-500/5 blur-[100px] -ml-32 -mb-32" />
                        </motion.div>
                    )}
                </AnimatePresence>
            </main>

            <ConfirmModal
                isOpen={showLogoutConfirm}
                onClose={() => setShowLogoutConfirm(false)}
                onConfirm={logout}
            />
        </div>
    );
};

export default DoctorDashboard;

import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
    ArrowLeft, Star, Clock, MapPin,
    Video, Hospital, Award, ThumbsUp,
    MessageCircle, ShieldCheck, IndianRupee,
    Calendar, CheckCircle2, ChevronRight, Share2
} from 'lucide-react';
import { motion } from 'framer-motion';
import Button from '../components/Button';
import { hospitals } from '../utils/mockData';
import { useAuth } from '../context/AuthContext';

const DoctorProfile = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { allHospitals, allDoctors } = useAuth();

    // Priority: 1. Live doctor data, 2. Live hospital data, 3. Mock fallback
    let doctor = allDoctors.find(d => d.id === id);
    let mainHospital = null;

    if (doctor) {
        mainHospital = allHospitals.find(h => h.id === doctor.hospitalId) || allHospitals.find(h => h.name === doctor.hospitalName);
    }

    if (!doctor) {
        hospitals.forEach(h => {
            const found = h.doctors.find(d => d.id === id);
            if (found) {
                doctor = found;
                mainHospital = h;
            }
        });
    }

    if (!doctor) {
        return (
            <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center bg-[#fcfdfe]">
                <h2 className="text-xl font-bold mb-4">Doctor not found</h2>
                <button onClick={() => navigate(-1)} className="btn-primary px-6 py-2 rounded-xl">Go Back</button>
            </div>
        );
    }

    return (
        <div className="container min-h-screen bg-[#fcfdfe] pb-32 animate-entrance relative">

            {/* Cinematic Hero Section */}
            <div className="relative h-[380px] w-full">
                <img
                    src={doctor.image}
                    alt={doctor.name}
                    className="w-full h-full object-cover"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-white via-white/20 to-transparent" />
                <div className="absolute inset-0 bg-gradient-to-b from-white/30 to-transparent" />

                {/* Header Actions */}
                <div className="absolute top-0 left-0 right-0 p-6 flex justify-between items-center z-10">
                    <button
                        onClick={() => navigate(-1)}
                        className="w-10 h-10 flex items-center justify-center rounded-full glass-dark backdrop-blur-md border border-white/20 active:scale-95 transition-transform"
                    >
                        <ArrowLeft size={20} className="text-white" />
                    </button>
                    <button
                        className="w-10 h-10 flex items-center justify-center rounded-full glass-dark backdrop-blur-md border border-white/20 active:scale-95 transition-transform"
                    >
                        <Share2 size={20} className="text-white" />
                    </button>
                </div>

                {/* Doctor Info Overlay */}
                <div className="absolute bottom-0 left-0 right-0 p-6 z-10">
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="flex flex-col gap-1"
                    >
                        <div className="flex items-center gap-2 mb-1">
                            {/* Clinical Status */}
                            <div className={`px-2.5 py-1 rounded-lg backdrop-blur-md border border-white/10 text-[10px] font-bold text-white uppercase tracking-wider ${doctor.status === 'Available' ? 'bg-success/40' : doctor.status === 'In Consultation' ? 'bg-orange-500/40' : 'bg-slate-500/40'}`}>
                                {doctor.status || 'ABSENT'}
                            </div>
                            {/* Verification Status */}
                            {doctor.status === 'PENDING_APPROVAL' && (
                                <div className="px-2.5 py-1 rounded-lg backdrop-blur-md border border-amber-500/50 bg-amber-600/60 text-[10px] font-black text-white uppercase tracking-widest flex items-center gap-1">
                                    <Clock size={10} /> Pending Verification
                                </div>
                            )}
                            <div className="flex items-center gap-1 px-2 py-1 rounded-lg bg-accent/90 backdrop-blur-md text-white">
                                <Star size={10} fill="currentColor" />
                                <span className="text-[10px] font-black">{doctor.rating || '4.5'}</span>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
                            <h1 className="text-3xl font-black text-white leading-tight tracking-tight">{doctor.name}</h1>
                            {doctor.status === 'APPROVED' || doctor.status === 'ACTIVE' ? (
                                <ShieldCheck size={24} className="text-blue-400" fill="currentColor" />
                            ) : (
                                <ShieldCheck size={24} className="text-white/30" />
                            )}
                        </div>
                        <p className="text-lg text-slate-200 font-medium">{doctor.specialty} ΓÇó {doctor.experience}+ Years</p>
                    </motion.div>
                </div>
            </div>

            {/* Quick Stats Grid */}
            <div className="px-6 -mt-8 relative z-20">
                <div className="glass p-4 rounded-[24px] shadow-xl flex justify-between items-center border-white/50">
                    <div className="flex flex-col items-center gap-1 flex-1 border-r border-border/50">
                        <div className="w-10 h-10 rounded-2xl bg-p-50 flex items-center justify-center mb-1">
                            <Award size={20} className="text-p-600" />
                        </div>
                        <span className="text-sm font-black text-main">{doctor.experience}+</span>
                        <span className="text-[10px] font-bold text-muted uppercase tracking-wide">Years</span>
                    </div>
                    <div className="flex flex-col items-center gap-1 flex-1 border-r border-border/50">
                        <div className="w-10 h-10 rounded-2xl bg-orange-50 flex items-center justify-center mb-1">
                            <Star size={20} className="text-orange-500" fill="currentColor" />
                        </div>
                        <span className="text-sm font-black text-main">{doctor.rating}</span>
                        <span className="text-[10px] font-bold text-muted uppercase tracking-wide">Rating</span>
                    </div>
                    <div className="flex flex-col items-center gap-1 flex-1 border-r border-border/50">
                        <div className="w-10 h-10 rounded-2xl bg-emerald-50 flex items-center justify-center mb-1">
                            <MessageCircle size={20} className="text-emerald-500" />
                        </div>
                        <span className="text-sm font-black text-main">{doctor.reviewsCount || 0}</span>
                        <span className="text-[10px] font-bold text-muted uppercase tracking-wide">Reviews</span>
                    </div>
                    <div className="flex flex-col items-center gap-1 flex-1">
                        <div className="w-10 h-10 rounded-2xl bg-blue-50 flex items-center justify-center mb-1">
                            <Clock size={20} className="text-blue-500" />
                        </div>
                        <span className="text-sm font-black text-main">{doctor.consultingTime || '15 mins'}</span>
                        <span className="text-[10px] font-bold text-muted uppercase tracking-wide">Wait</span>
                    </div>
                </div>
            </div>

            <div className="px-6 mt-8 flex flex-col gap-6">

                {/* About Section */}
                <div>
                    <h3 className="text-lg font-black text-main mb-3 flex items-center gap-2">
                        About Doctor
                    </h3>
                    <p className="text-sm text-muted leading-relaxed font-medium">
                        Dr. {doctor.name.split(' ').pop()} is a highly skilled {doctor.specialty} with over {doctor.experience} years of experience in treating complex cases. Dedicated to providing compassionate care using the latest medical advancements.
                    </p>
                </div>

                {/* Consultation Fees */}
                {doctor.fees && (
                    <div>
                        <h3 className="text-lg font-black text-main mb-3 flex items-center gap-2">
                            Consultation Fees
                        </h3>
                        <div className="grid grid-cols-2 gap-3">
                            <div className="p-4 rounded-[24px] bg-white border border-border/50 flex flex-col items-center gap-1 shadow-sm">
                                <span className="text-[10px] font-bold text-muted uppercase tracking-wider">Online</span>
                                <span className="text-xl font-black text-p-600">Γé╣{doctor.fees.online}</span>
                            </div>
                            <div className="p-4 rounded-[24px] bg-white border border-border/50 flex flex-col items-center gap-1 shadow-sm">
                                <span className="text-[10px] font-bold text-muted uppercase tracking-wider">Hospital</span>
                                <span className="text-xl font-black text-main">Γé╣{doctor.fees.offline}</span>
                            </div>
                        </div>
                    </div>
                )}

                {/* Availability */}
                {doctor.availability?.available && (
                    <div>
                        <h3 className="text-lg font-black text-main mb-3 flex items-center gap-2">
                            Next Available Slots
                        </h3>
                        <div className="flex flex-wrap gap-2">
                            {doctor.availability.available.slice(0, 4).map((time, i) => (
                                <div key={i} className="px-4 py-2 rounded-xl bg-p-50 text-p-700 text-xs font-bold border border-p-100">
                                    {time}
                                </div>
                            ))}
                            {doctor.availability.available.length > 4 && (
                                <div className="px-4 py-2 rounded-xl bg-slate-50 text-muted text-xs font-bold border border-slate-100">
                                    +{doctor.availability.available.length - 4} More
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* Practice Locations */}
                {doctor.hospitals && (
                    <div>
                        <h3 className="text-lg font-black text-main mb-3 flex items-center gap-2">
                            Practice Locations
                        </h3>
                        <div className="flex flex-col gap-3">
                            {doctor.hospitals.map((h, i) => (
                                <div key={i} className="flex items-center gap-4 p-4 rounded-[24px] bg-white border border-border/50 shadow-sm">
                                    <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center">
                                        <Hospital size={20} className="text-slate-500" />
                                    </div>
                                    <div className="flex-1">
                                        <h4 className="text-sm font-black text-main">{h}</h4>
                                        {h === mainHospital?.name && (
                                            <span className="text-[10px] font-bold text-success uppercase tracking-wide">Primary Location</span>
                                        )}
                                    </div>
                                    <div className="w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center">
                                        <ChevronRight size={16} className="text-slate-400" />
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Patient Reviews Preview */}
                {doctor.reviews && doctor.reviews.length > 0 && (
                    <div className="mb-8">
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="text-lg font-black text-main">Patient Stories</h3>
                            <button className="text-xs font-bold text-p-600">View All</button>
                        </div>
                        {doctor.reviews.slice(0, 2).map((review) => (
                            <div key={review.id} className="mb-4 p-4 rounded-[24px] bg-slate-50/50 border border-border/30">
                                <div className="flex justify-between items-center mb-2">
                                    <span className="text-xs font-bold text-main">{review.user}</span>
                                    <div className="flex items-center gap-0.5">
                                        <Star size={10} className="text-orange-400" fill="currentColor" />
                                        <span className="text-[10px] font-bold text-orange-400">{review.rating}.0</span>
                                    </div>
                                </div>
                                <p className="text-xs text-muted leading-relaxed font-medium">"{review.comment}"</p>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            {/* Floating Booking Island */}
            {doctor.fees && mainHospital && (
                <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[calc(100%-32px)] max-w-[430px] p-2 rounded-[32px] glass shadow-2xl z-[100] border-white/60 flex items-center gap-2 backdrop-blur-xl">
                    <button
                        onClick={() => navigate(`/book-appointment/${mainHospital.id}?doctor=${doctor.id}&type=home`)}
                        className="flex-1 h-14 rounded-[24px] flex flex-col items-center justify-center gap-0.5 bg-emerald-50 hover:bg-emerald-100 transition-colors active:scale-95"
                    >
                        <span className="text-[11px] font-black text-emerald-700">≡ƒÅá Home</span>
                        <span className="text-[10px] font-bold text-emerald-500">Visit</span>
                    </button>
                    <button
                        onClick={() => navigate(`/book-appointment/${mainHospital.id}?doctor=${doctor.id}&type=online`)}
                        className="flex-1 h-14 rounded-[24px] flex flex-col items-center justify-center gap-0.5 bg-p-50 hover:bg-p-100 transition-colors active:scale-95"
                    >
                        <span className="text-[11px] font-black text-p-600">≡ƒô╣ Online</span>
                        <span className="text-[10px] font-bold text-p-400">Γé╣{doctor.fees.online}</span>
                    </button>
                    <button
                        onClick={() => navigate(`/book-appointment/${mainHospital.id}?doctor=${doctor.id}&type=hospital`)}
                        className="flex-[1.3] h-14 rounded-[24px] flex flex-col items-center justify-center gap-0.5 btn-primary shadow-lg shadow-p-600/20 active:scale-95 border-none"
                    >
                        <span className="text-[11px] font-black text-white">≡ƒÅÑ Hospital</span>
                        <span className="text-[10px] font-bold text-white/80">Γé╣{doctor.fees.offline}</span>
                    </button>
                </div>
            )}
            {doctor.fees && !mainHospital && (
                <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[calc(100%-48px)] max-w-[420px] p-2 rounded-[32px] glass shadow-2xl z-[100] border-white/60 flex items-center gap-3 backdrop-blur-xl">
                    <button onClick={() => navigate(-1)} className="flex-1 h-14 rounded-[24px] flex items-center justify-center gap-2 btn-primary border-none">
                        <span className="text-[13px] font-black text-white">Go Back</span>
                    </button>
                </div>
            )}
        </div>
    );
};

export default DoctorProfile;

