            const updated = billing.currentItems.map(i =>
                i.id === medicine.id ? { ...i, qty: i.qty + incomingQty } : i
            );
            syncBillingTotals(updated);
        } else {
            const updated = [...billing.currentItems, { ...medicine, qty: incomingQty }];
            syncBillingTotals(updated);
        }
    };

