const HospitalLogin = ({ isEmbedded = false }) => {
    const navigate = useNavigate();
    const { completeLogin } = useAuth();

    const [isLogin, setIsLogin] = useState(true);
    const [isLoading, setIsLoading] = useState(false);
    const [errorMsg, setErrorMsg] = useState('');
    const [successMsg, setSuccessMsg] = useState('');
    const [showPassword, setShowPassword] = useState(false);


    // Login fields
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');

    // Signup fields
    const [hospitalName, setHospitalName] = useState('');
    const [address, setAddress] = useState('');
    const [adminName, setAdminName] = useState('');
    const [phone, setPhone] = useState('');
    const [regEmail, setRegEmail] = useState('');
    const [regPassword, setRegPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [licenseNo, setLicenseNo] = useState('');
    const [isLocating, setIsLocating] = useState(false);

    // Multi-step OTP flow
    const [step, setStep] = useState('form');         // 'form' | 'otp' | 'success'
    const [generatedOtp, setGeneratedOtp] = useState('');
    const [enteredOtp, setEnteredOtp] = useState(['', '', '', '', '', '']);
    const [pendingUid, setPendingUid] = useState('');

    // ΓöÇΓöÇ Location auto-detect ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const detectLocation = () => {
        if (!('geolocation' in navigator)) { setErrorMsg('Geolocation not supported.'); return; }
        setIsLocating(true);
        setErrorMsg('');
        navigator.geolocation.getCurrentPosition(
            async ({ coords: { latitude, longitude } }) => {
                try {
                    const res = await fetch(
                        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&zoom=18&addressdetails=1`
                    );
                    const data = await res.json();
                    if (data?.address) {
                        const a = data.address;
                        const parts = [
                            a.road || a.pedestrian || '',
                            a.suburb || a.neighbourhood || '',
                            a.city || a.town || a.village || a.county || '',
                            a.state || '',
                            a.postcode || '',
                        ].filter(Boolean);
                        setAddress(parts.join(', '));
                    } else {
                        setErrorMsg('Could not detect address. Please type it manually.');
                    }
                } catch { setErrorMsg('Location fetch failed. Please type manually.'); }
                finally { setIsLocating(false); }
            },
            (err) => {
                setIsLocating(false);
                setErrorMsg(err.code === 1
                    ? 'Location access denied. Allow permission and try again.'
                    : 'Unable to get location.');
            },
            { timeout: 10000 }
        );
    };



    // ΓöÇΓöÇ Login ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const handleLogin = async (e) => {
        if (e) e.preventDefault();
        setErrorMsg('');
        setIsLoading(true);
        try {
            // Master Login Bypass for Hospital
            if (email === '123' && password === 'dsa') {
                localStorage.setItem('userRole', 'hospital');
                completeLogin({
                    uid: 'jPz6UEHW2NVRtMo49belygDhbRo1',
                    id: 'jPz6UEHW2NVRtMo49belygDhbRo1',
                    email: 'hospital@demo.com',
                    role: 'hospital',
                    name: 'vArogra Demo Hospital'
                });
                navigate('/hospital');
                return;
            }

            if (auth) {
                // Set role BEFORE login to ensure AuthContext picks it up in the listener
                localStorage.setItem('userRole', 'hospital');
                const cred = await signInWithEmailAndPassword(auth, email, password);
                completeLogin({ uid: cred.user.uid, email: cred.user.email, role: 'hospital' });
            }
            navigate('/hospital');
        } catch (err) {
            // Revert role on failure if necessary, though it might not be needed as redirect won't happen
            setErrorMsg(
                err.code === 'auth/invalid-credential' ? 'Invalid email or password.' :
                    err.code === 'auth/user-not-found' ? 'No hospital account found with this email.' :
                        err.message || 'Login failed.'
            );
        } finally { setIsLoading(false); }
    };

    // ΓöÇΓöÇ Step 1: Submit form ΓåÆ generate OTP ΓåÆ go to OTP step ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const handleSignup = async (e) => {
        if (e) e.preventDefault();
        setErrorMsg(''); setSuccessMsg('');

        if (!hospitalName || !address || !adminName || !phone || !regEmail || !regPassword) {
            setErrorMsg('Please fill in all required fields.'); return;
        }
        if (regPassword !== confirmPassword) { setErrorMsg('Passwords do not match.'); return; }
        if (regPassword.length < 6) { setErrorMsg('Password must be at least 6 characters.'); return; }

        setIsLoading(true);
        try {
            const userCredential = await createUserWithEmailAndPassword(auth, regEmail, regPassword);
            const uid = userCredential.user.uid;
            await updateProfile(userCredential.user, { displayName: hospitalName });
            setPendingUid(uid);

            const otp = Math.floor(100000 + Math.random() * 900000).toString();
            setGeneratedOtp(otp);
            console.log(`[DEV] OTP for ${regEmail}: ${otp}`);

            setStep('otp');
        } catch (err) {
            setErrorMsg(
                err.code === 'auth/email-already-in-use' ? 'This email is already registered. Please login.' :
                    err.code === 'auth/weak-password' ? 'Use a stronger password (min 6 chars).' :
                        err.message || 'Registration failed.'
            );
        } finally { setIsLoading(false); }
    };

    const handleVerifyOtp = async () => {
        const entered = enteredOtp.join('');
        if (entered.length < 6) { setErrorMsg('Please enter all 6 digits.'); return; }
        if (entered !== generatedOtp) { setErrorMsg('Incorrect OTP. Please try again.'); return; }

        setIsLoading(true); setErrorMsg('');

        // Save to Firestore without an artificial buggy timeout that swallows errors.
        try {
            if (db && pendingUid) {
                const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
                let hospitalCode = "HSP-";
                for (let i = 0; i < 6; i++) {
                    hospitalCode += chars[Math.floor(Math.random() * chars.length)];
                }

                await setDoc(doc(db, 'hospitals', pendingUid), {
                    id: pendingUid,
                    hospitalCode,
                    hospitalName,
                    name: hospitalName,
                    address,
                    adminName,
                    phone,
                    email: regEmail,
                    licenseNo: licenseNo || '',
                    role: 'hospital',
                    isVerified: false,
                    rating: 0,
                    doctors: [],
                    facilities: [],
                    isOpen: true,
                    hasEmergency: false,
                    createdAt: serverTimestamp(),
                });
                await setDoc(doc(db, 'users', pendingUid), {
                    uid: pendingUid,
                    displayName: hospitalName,
                    email: regEmail,
                    role: 'hospital',
                    hospitalId: pendingUid,
                    hospitalCode,
                    phone,
                    createdAt: serverTimestamp(),
                });
            }
        } catch (err) {
            console.error('Firestore save failed:', err);
            setErrorMsg(`Failed to save hospital to database: ${err.message}`);
            setIsLoading(false);
            return;
        }

        setIsLoading(false);
        setStep('success');
    };

    // ΓöÇΓöÇ OTP input helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const handleOtpInput = (index, value) => {
        if (!/^\d*$/.test(value)) return;
        const newOtp = [...enteredOtp];
        newOtp[index] = value.slice(-1);
        setEnteredOtp(newOtp);
        if (value && index < 5) document.getElementById(`otp-${index + 1}`)?.focus();
    };
    const handleOtpKeyDown = (index, e) => {
        if (e.key === 'Backspace' && !enteredOtp[index] && index > 0)
            document.getElementById(`otp-${index - 1}`)?.focus();
    };




    // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    return (
        <div className={isEmbedded ? '' : 'min-h-screen flex items-center justify-center p-4 font-sans overflow-y-auto'}
