                                <CheckCircle2 size={16} className="shrink-0" />{successMsg}
                            </motion.div>
                        )}
                    </AnimatePresence>

                    <AnimatePresence mode="wait">

                        {/* ΓòÉΓòÉ LOGIN ΓòÉΓòÉ */}
                        {isLogin && step === 'form' && (
                            <motion.form key="login" initial={{ opacity: 0, x: -15 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: 15 }} transition={{ duration: 0.3 }}
