        { name: 'Complete Blood Count (CBC)', date: '2026-02-01', status: 'Normal', values: [{ label: 'WBC', val: '11,200 /┬╡L Γåæ', ok: false }, { label: 'CRP', val: '32 mg/L Γåæ', ok: false }] },
    ],
    3: [
        { name: 'ECG (12-lead)', date: '2026-02-20', status: 'Abnormal', values: [{ label: 'Rhythm', val: 'Sinus rhythm', ok: true }, { label: 'Finding', val: 'Mild ST depression leads V4-V6', ok: false }] },
        { name: 'Lipid Profile', date: '2026-02-18', status: 'Abnormal', values: [{ label: 'LDL', val: '142 mg/dL Γåæ', ok: false }, { label: 'HDL', val: '38 mg/dL Γåô', ok: false }, { label: 'Triglycerides', val: '210 mg/dL Γåæ', ok: false }] },
        { name: 'HbA1c', date: '2026-02-18', status: 'Borderline', values: [{ label: 'Value', val: '6.1% (Borderline)', ok: null }] },
