                            </div>
                        </div>
                        <span style={{ fontSize: '0.7rem', fontWeight: '700', padding: '3px 10px', borderRadius: '10px', background: `${statusColor[r.status] || 'gray'}18`, color: statusColor[r.status] || 'var(--text-muted)' }}>{r.status}</span>
                    </button>
