                        </div>
                        <p style={{ fontSize: '0.65rem', color: 'var(--text-muted)', textAlign: 'center' }}>
                            By confirming, you verify the accuracy of this digital prescription. MedAIΓäó results are advisory and must be reviewed by the clinical specialist.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
};

