                                {isEmergency ? 'PROTOCOL ALPHA' : 'SYSTEM SYNCED'}
                            </span>
                        </div>
                    </div>
                    <div>
                        <AnimatePresence>
                            {pendingQueue.length > 0 ? (
                                pendingQueue.map((item, i) => (
                                    <QueueItem
