                                </motion.div>
                            )}
                        </AnimatePresence>

                        {!isEmergency && (
                            <div style={{ marginTop: '2.5rem' }}>
                                <motion.button
                                    whileHover={{ background: 'rgba(59, 130, 246, 0.05)' }}
