                    }}>
                        {doc.name.split(' ').pop()[0]}
                    </div>
                    <div>
                        <h4 style={{ fontSize: '1.2rem', fontWeight: '700', marginBottom: '4px' }}>{doc.name}</h4>
                        <span className="pill" style={{ background: 'rgba(255,255,255,0.05)', color: 'var(--text-secondary)' }}>
